INSERT INTO news (`id`, `title`, `slug`, `content`, `excerpt`, `image`, `image_type`, `video_url`, `video_path`, `category_id`, `author_id`, `featured_image`, `status`, `news_type`, `is_breaking`, `featured`, `breaking_news`, `views`, `likes_count`, `engagement_score`, `share_count`, `comment_count`, `meta_title`, `meta_description`, `meta_keywords`, `published_at`, `source_url`, `source_name`, `created_at`, `updated_at`, `sentiment_score`, `sentiment_label`, `urgency`, `credibility_status`, `auto_flagged`, `time_status`) VALUES ('392', 'Weather tracker: Thunderstorms drench UAE and Saudi Arabia', 'weather-tracker-thunderstorms-drench-uae-and-saudi-arabia', '<p>Abnormally strong jet stream triggers deluge in Middle East, while north Africa braces for 60-80mph gustsAn unusual weather pattern unleashed severe thunderstorms across parts of the Middle East last week, battering countries including the United Arab Emirates and Saudi Arabia. The Arabian peninsula typically dominated by arid desert climates received up to 150mm of rain in just a few days.The deluge was caused by an abnormally strong jet stream, which helped a deep area of low pressure to develop north of Saudi Arabia. This, in turn, drew moist tropical air from the Indian Ocean and triggered intense storms.</p>

