INSERT INTO news (`id`, `title`, `slug`, `content`, `excerpt`, `image`, `image_type`, `video_url`, `video_path`, `category_id`, `author_id`, `featured_image`, `status`, `news_type`, `is_breaking`, `featured`, `breaking_news`, `views`, `likes_count`, `engagement_score`, `share_count`, `comment_count`, `meta_title`, `meta_description`, `meta_keywords`, `published_at`, `source_url`, `source_name`, `created_at`, `updated_at`, `sentiment_score`, `sentiment_label`, `urgency`, `credibility_status`, `auto_flagged`, `time_status`) VALUES ('390', 'News outlets falsely report Somaliland called for extradition of Ilhan Omar', 'news-outlets-falsely-report-somaliland-called-for-extradition-of-ilhan-omar', '<p>Reports, based on X post from unofficial account, follow JD Vances accusations and threats of finding legal remediesSign up for the Breaking News US email to get newsletter alerts in your inboxSeveral news outlets have falsely reported that Somalilands government called for the extradition of Ilhan Omar, basing their stories on a post from an X account that does not represent the state despite its claims to the contrary.Fox News, the New York Post, Sinclair Broadcast Groups the National News Desk and the Independent ran stories on the US representative. The reports centred on a post by RepOfSomaliland in reaction to claims by JD Vance that Omar had committed immigration fraud, which echoed prior allegations against the Somali-born Minnesota Democrat that she has vehemently denied.</p>

<p><em><strong>Source:</strong> <a href=\"https://www.theguardian.com/us-news/2026/mar/30/ilhan-omar-false-reports-somaliland\" target=\"_blank\" rel=\"noopener\">The Guardian</a></em></p>

