<p><em><strong>Source:</strong> <a href=\"https://www.theguardian.com/artanddesign/2026/mar/27/african-guernica-dumile-feni-on-display-alongside-picasso\" target=\"_blank\" rel=\"noopener\">The Guardian</a></em></p>
<p><strong><a href=\"https://www.theguardian.com/artanddesign/2026/mar/27/african-guernica-dumile-feni-on-display-alongside-picasso\" target=\"_blank\" rel=\"noopener\">Read full story on The Guardian</a></strong></p>', 'Piece by late South African artist Dumile Feni is part of new series History Doesnt Repeat Itself, But It Does Rhyme On the second floor of the Reina Sofa, in the very spot where Picassos Guernica was first exhibited when it arrived in the Madrid...', 'uploads/news/69c75d335eb72.png', 'manual', '', NULL, '1', '1', NULL, 'published', 'rss_import', '1', '0', '0', '0', '0', '0.00', '0', '0', NULL, NULL, NULL, '2026-03-30 01:48:38', 'https://www.theguardian.com/artanddesign/2026/mar/27/african-guernica-dumile-feni-on-display-alongside-picasso', NULL, '2026-03-28 09:45:22', '2026-03-30 01:48:38', '0.00', 'neutral', 'medium', 'PENDING', '0', 'older');
INSERT INTO news (`id`, `title`, `slug`, `content`, `excerpt`, `image`, `image_type`, `video_url`, `video_path`, `category_id`, `author_id`, `featured_image`, `status`, `news_type`, `is_breaking`, `featured`, `breaking_news`, `views`, `likes_count`, `engagement_score`, `share_count`, `comment_count`, `meta_title`, `meta_description`, `meta_keywords`, `published_at`, `source_url`, `source_name`, `created_at`, `updated_at`, `sentiment_score`, `sentiment_label`, `urgency`, `credibility_status`, `auto_flagged`, `time_status`) VALUES ('286', 'UN’s landmark slavery ruling energises African Union’s fight for reparations', 'un-s-landmark-slavery-ruling-energises-african-union-s-fight-for-reparations', '<p>UN votes to describe slave trade as gravest crime against humanityDespite resistance from states who had role in chattel slavery, many feel this is an idea whose time has comeJohn Mahama knows a thing or two about beating the establishment. On Wednesday, less than two years after completing a remarkable comeback as Ghanas president with a landslide defeat of the ruling party candidate, he rallied the world to ratify a landmark vote against transatlantic chattel slavery, despite major opposition from the same western entities that drove it for centuries.The resolution to declare the practice as the gravest crime against humanity passed with a decisive majority at the UN general assembly and has been largely welcomed across Africa. Yet the details of the tally reveal a world still deeply divided on the gravity of the sin of enslaving more than 15 million people as chattel over the course of 400 years.</p>

<p><em><strong>Source:</strong> <a href=\"https://www.theguardian.com/news/2026/mar/27/un-slavery-ruling-african-union-reparations-slavery-analysis\" target=\"_blank\" rel=\"noopener\">The Guardian</a></em></p>

<p><strong><a href=\"https://www.theguardian.com/news/2026/mar/27/un-slavery-ruling-african-union-reparations-slavery-analysis\" target=\"_blank\" rel=\"noopener\">Read full story on The Guardian</a></strong></p>', 'UN votes to describe slave trade as gravest crime against humanityDespite resistance from states who had role in chattel slavery, many feel this is an idea whose time has comeJohn Mahama knows a thing or two about beating the establishment. On...', '', 'manual', '', NULL, '1', '1', NULL, 'published', 'rss_import', '0', '0', '0', '0', '0', '0.00', '0', '0', NULL, NULL, NULL, '2026-03-28 15:32:56', 'https://www.theguardian.com/news/2026/mar/27/un-slavery-ruling-african-union-reparations-slavery-analysis', NULL, '2026-03-28 09:45:21', '2026-03-28 23:37:21', '0.00', 'neutral', 'medium', 'PENDING', '0', 'older');
